class TrieNode:
    def __init__(self): self.ch = {}; self.end = False
class Trie:
    def __init__(self): self.root = TrieNode()
    def insert(self, word):
        cur = self.root
        for c in word:
            if c not in cur.ch: cur.ch[c] = TrieNode()
            cur = cur.ch[c]
        cur.end = True
    def search(self, word):
        cur = self._find(word); return cur is not None and cur.end
    def startsWith(self, prefix):
        return self._find(prefix) is not None
    def _find(self, s):
        cur = self.root
        for c in s:
            if c not in cur.ch: return None
            cur = cur.ch[c]
        return cur

